+#endif
+
   base64data = output = malloc((insize + 2) / 3 * 4 + 1);
   if(!output)
     return CURLE_OUT_OF_MEMORY;
"
  },
  {
    "file": "lib/cookie.c",
    "line": 147,
    "severity": "high",
    "description": "Cookie domain matching bypass vulnerability in cookie_tailmatch function. The pointer arithmetic for subdomain validation was changed from `hostname + hostname_len - cookie_domain_len - 1` to `hostname + hostname_len - cookie_domain_len`, removing the critical `-1` offset. This causes the function to check the wrong character position when validating if a hostname is a proper subdomain of a cookie domain. Instead of verifying that the separator character before the domain suffix is a dot (.), the function now checks a character within the domain itself. This allows cookies set for a domain (e.g., 'example.com') to be incorrectly matched against hostnames like 'notexample.com', bypassing proper cookie scope validation per RFC 6265.",
    "fix_patch": "--- a/lib/cookie.c
+++ b/lib/cookie.c
@@ -144,7 +144,7 @@ static bool cookie_tailmatch(const char *cookie_domain,
    */
   if(hostname_len == cookie_domain_len)
     return TRUE;
-  if('.' == *(hostname + hostname_len - cookie_domain_len))
+  if('.' == *(hostname + hostname_len - cookie_domain_len - 1))
     return TRUE;
   return FALSE;
 }
"
  }
]

